import React, { useState } from "react";
import "../Styles/dashboard.css";

const NotificationPanel = () => {
    const [activeTab, setActiveTab] = useState("notification");

    const tabs = [
        { id: "notification", label: "Notification" },
        { id: "circular", label: "Circular" },
        { id: "lms", label: "LMS Notification" },
        { id: "announcement", label: "Student Announcement" }
    ];

    const notifications = [
        {
            id: 1,
            title: "Admit Card Generated for BTech Semester - 7 Regular Exam",
            date: "09-Oct",
            type: "notification"
        },
        {
            id: 2,
            title: "Admit Card Generated for BTech Semester - 7 Supplementary Exam",
            date: "09-Oct",
            type: "notification"
        },
        {
            id: 3,
            title: "Diwali Vacation Circular",
            date: "01-Oct",
            type: "circular"
        }
    ];

    const filteredNotifications = notifications.filter(n => n.type === activeTab || (activeTab === 'notification' && n.type === 'notification'));

    return (
        <div className="notification-panel">
            <div className="panel-header">
                <h3><i className="fas fa-bell"></i> NOTIFICATION</h3>
            </div>

            <div className="notification-tabs">
                {tabs.map(tab => (
                    <button
                        key={tab.id}
                        className={`tab-btn ${activeTab === tab.id ? "active" : ""}`}
                        onClick={() => setActiveTab(tab.id)}
                    >
                        {tab.label}
                    </button>
                ))}
            </div>

            <div className="notification-list">
                {filteredNotifications.length > 0 ? (
                    filteredNotifications.map(notif => (
                        <div key={notif.id} className="notification-item">
                            <div className="notif-icon-box">
                                <i className="fas fa-bell"></i>
                            </div>
                            <div className="notif-content">
                                <p className="notif-title">{notif.title}</p>
                            </div>
                            <div className="notif-date">{notif.date}</div>
                        </div>
                    ))
                ) : (
                    <div className="no-record">
                        <i className="fas fa-exclamation-circle"></i> No Record Found
                    </div>
                )}
            </div>
        </div>
    );
};

export default NotificationPanel;
